package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringWriter;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithEscape() {
        // Given
        char escape = '\\';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withEscape(escape);

        // Then
        assertNotNull(result);
        assertNotSame(csvFormat, result);
        assertEquals(escape, result.getEscapeCharacter());
    }

    @Test
    public void testWithEscape_WhenCharacterIsNull() {
        // Given
        char escape = '\\';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = csvFormat.withEscape(null);

        // Then
        assertNotNull(result);
        assertNotSame(csvFormat, result);
        assertNull(result.getEscapeCharacter());
    }

    @Test
    public void testWithEscape_PrivateMethodInvocation() throws Exception {
        // Given
        char escape = '\\';
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVFormat spyCsvFormat = spy(csvFormat);

        // When
        CSVFormat result = (CSVFormat) invokePrivateMethod(spyCsvFormat, "withEscape", char.class, escape);

        // Then
        assertNotNull(result);
        assertNotSame(csvFormat, result);
        assertEquals(escape, result.getEscapeCharacter());
    }

    private Object invokePrivateMethod(Object object, String methodName, Class<?> parameterType, Object argument) throws Exception {
        java.lang.reflect.Method method = object.getClass().getDeclaredMethod(methodName, parameterType);
        method.setAccessible(true);
        return method.invoke(object, argument);
    }
}
